const config=require("./config");async function testOpenSeaOrders(){console.log("🧪 Testing OpenSea API v2 Orders endpoint...");const testWallet="0x834711f749fe36dc4a5ae135267b88d0aaad8f3d";try{const apiKey=config.opensea.apiKey;console.log(`🔍 Step 1: Fetching events for wallet: ${testWallet}`);const eventsResponse=await fetch(`https://api.opensea.io/api/v2/events/accounts/${testWallet}?event_type=sale&event_type=transfer&event_type=mint&limit=10`,{headers:{"X-API-KEY":apiKey,Accept:"application/json"}});if(eventsResponse.ok){const eventsData=await eventsResponse.json();if(console.log(`✅ Found ${eventsData.asset_events?.length||0} events`),eventsData.asset_events&&eventsData.asset_events.length>0){const eventsWithOrders=eventsData.asset_events.filter((event=>event.order_hash||event.transaction));console.log(`📊 Found ${eventsWithOrders.length} events with order/transaction data`);for(let i=0;i<Math.min(3,eventsWithOrders.length);i++){const event=eventsWithOrders[i];if(console.log(`\n--- Event ${i+1} ---`),console.log(`Type: ${event.event_type}`),console.log(`Transaction: ${event.transaction||"N/A"}`),console.log(`Order Hash: ${event.order_hash||"N/A"}`),event.order_hash){console.log(`🔍 Step 2: Fetching order details for hash: ${event.order_hash}`);const chains=["ethereum","base","polygon"],protocols=["0x0000000000000068f116a894984e2db1123eb395","0x00000000000001ad428e4906aE43D8F9852d0dD6"];for(const chain of chains)for(const protocol of protocols)try{const orderResponse=await fetch(`https://api.opensea.io/api/v2/orders/chain/${chain}/protocol/${protocol}/order_hash/${event.order_hash}`,{method:"GET",headers:{"X-API-KEY":apiKey,Accept:"application/json"}});if(orderResponse.ok){const orderData=await orderResponse.json();if(console.log(`✅ Found order on ${chain} with protocol ${protocol}:`),orderData.order){const order=orderData.order;if(console.log(`  Order Hash: ${order.order_hash}`),order.price&&order.price.current){const price=order.price.current,priceValue=parseFloat(price.value)/Math.pow(10,price.decimals);console.log(`  Price: ${priceValue} ${price.currency}`)}if(order.protocol_data&&order.protocol_data.parameters){const params=order.protocol_data.parameters;if(console.log(`  Offerer: ${params.offerer}`),console.log(`  Start Time: ${new Date(1e3*parseInt(params.startTime)).toLocaleString()}`),console.log(`  End Time: ${new Date(1e3*parseInt(params.endTime)).toLocaleString()}`),params.offer&&params.offer.length>0){const offer=params.offer[0];console.log(`  Offer: Token ${offer.token}, ID ${offer.identifierOrCriteria}, Amount ${offer.startAmount}`)}if(params.consideration&&params.consideration.length>0){const consideration=params.consideration[0],considerationValue=parseFloat(consideration.startAmount)/Math.pow(10,18);console.log(`  Consideration: ${considerationValue} ETH to ${consideration.recipient}`)}}break}}}catch(error){}}await new Promise((resolve=>setTimeout(resolve,1e3)))}}else console.log("📭 No events found for this wallet")}else console.log(`❌ Error fetching events: ${eventsResponse.status} ${eventsResponse.statusText}`)}catch(error){console.error("❌ Error:",error.message)}}testOpenSeaOrders();